import {
  assertFoilEdgeAdmission,
  createStaticFoilAdmissionProof,
  FoilAdmissionDeferredError,
  FoilAdmissionRejectedError,
  FoilEdgeRuntime,
  isAccept,
  isDefer,
  isReject,
  Verdict,
  verifyFoilAdmissionProof,
  ZERO_DEFICIT_FOIL_CERTIFICATE,
} from '../foil-edge-gate';

const acceptedProof = createStaticFoilAdmissionProof(
  ZERO_DEFICIT_FOIL_CERTIFICATE
);

if (!assertFoilEdgeAdmission(acceptedProof).accepted) {
  throw new Error('expected zero-deficit proof to pass the hard gate');
}

const runtime = new FoilEdgeRuntime();
let verifierCalls = 0;
const meteredRuntime = new FoilEdgeRuntime({
  verifier: (proof) => {
    verifierCalls += 1;
    return assertFoilEdgeAdmission(proof);
  },
});
const executed = runtime.executeTopology(
  {
    ggGraph: new Uint8Array([1]),
    zkProof: acceptedProof,
    tritonAdmission: {
      phase: 'race-fold-present',
      clockPhase: 0,
      carrierKey: 11,
    },
  },
  () => 'webgpu-dispatch'
);

if (executed !== 'webgpu-dispatch') {
  throw new Error('expected admitted topology to execute');
}

const meteredExecuted = meteredRuntime.executeTopology(
  {
    ggGraph: new Uint8Array([1]),
    zkProof: acceptedProof,
    tritonAdmission: {
      phase: 'race-fold-present',
      clockPhase: 0,
      carrierKey: 11,
    },
  },
  () => 'metered-webgpu-dispatch'
);

if (meteredExecuted !== 'metered-webgpu-dispatch') {
  throw new Error('expected metered admitted topology to execute');
}

try {
  meteredRuntime.executeTopology(
    {
      ggGraph: new Uint8Array([1]),
      zkProof: acceptedProof,
      tritonAdmission: {
        phase: 'fork-future',
        clockPhase: 0,
      },
    },
    () => 'should-not-dispatch'
  );
  throw new Error('expected wrong Triton clock slot to fail before FOIL dispatch');
} catch (error) {
  if (!(error instanceof FoilAdmissionRejectedError)) {
    throw error;
  }
  if (!error.message.includes('triton-clock-phase-mismatch')) {
    throw error;
  }
}

try {
  meteredRuntime.executeTopology(
    {
      ggGraph: new Uint8Array([1]),
      zkProof: acceptedProof,
      tritonAdmission: {
        phase: 'fork-future',
        clockPhase: 1,
        forkBudget: 0,
      },
    },
    () => 'should-not-dispatch'
  );
  throw new Error('expected exhausted fork budget to defer before FOIL dispatch');
} catch (error) {
  if (!(error instanceof FoilAdmissionRejectedError)) {
    throw error;
  }
  if (!error.message.includes('fork-budget-exhausted')) {
    throw error;
  }
}

try {
  meteredRuntime.executeTopology(
    {
      ggGraph: new Uint8Array([1]),
      zkProof: acceptedProof,
      tritonAdmission: {
        phase: 'race-fold-present',
        clockPhase: 0,
        carrierKey: 1,
        seenCanonicalC2Keys: new Set([0]),
      },
    },
    () => 'should-not-dispatch'
  );
  throw new Error('expected C2 duplicate to fail before FOIL dispatch');
} catch (error) {
  if (!(error instanceof FoilAdmissionRejectedError)) {
    throw error;
  }
  if (!error.message.includes('c2-duplicate-carrier')) {
    throw error;
  }
}

const preflightMetrics = meteredRuntime.metrics();
if (verifierCalls !== 1) {
  throw new Error(
    `expected Triton preflight drops to bypass verifier; verifierCalls=${verifierCalls}`
  );
}
if (preflightMetrics.verifierCalls !== 1) {
  throw new Error(
    `expected runtime metrics to record one verifier call; got ${preflightMetrics.verifierCalls}`
  );
}
if (preflightMetrics.tritonPreflightDropped !== 3) {
  throw new Error(
    `expected three Triton preflight drops; got ${preflightMetrics.tritonPreflightDropped}`
  );
}
if (preflightMetrics.executedTopologies !== 1) {
  throw new Error(
    `expected one metered execution; got ${preflightMetrics.executedTopologies}`
  );
}

const rejectedProof = createStaticFoilAdmissionProof({
  ...ZERO_DEFICIT_FOIL_CERTIFICATE,
  classicalDeficit: 1,
});

try {
  runtime.executeTopology(
    { ggGraph: new Uint8Array([1]), zkProof: rejectedProof },
    () => 'should-not-dispatch'
  );
  throw new Error('expected nonzero-deficit proof to fail closed');
} catch (error) {
  if (!(error instanceof FoilAdmissionRejectedError)) {
    throw error;
  }
}

// ── New: the defer/abstain path (the canonical-verdict value-add) ──────
//
// A structurally well-formed proof whose verification has not yet settled under
// the constant bound (verificationCost > constantBound) is NOT a forgery — it is
// latent / recheck-later. The old bool squashed this into a hard reject; the
// canonical verdict surfaces it as Abstain (defer).

// The forged Decline path carries the canonical Decline verdict (sign -1).
const declineResult = verifyFoilAdmissionProof(rejectedProof);
if (declineResult.accepted) {
  throw new Error('expected nonzero-deficit proof to not be accepted');
}
if (declineResult.verdict !== Verdict.Decline || !isReject(declineResult.verdict)) {
  throw new Error('expected forged proof to carry the Decline verdict');
}

// The latent proof: well-formed but cost exceeds the constant bound → Abstain.
const latentProof = createStaticFoilAdmissionProof(ZERO_DEFICIT_FOIL_CERTIFICATE, {
  verificationCost: 2,
  constantBound: 1,
});

const latentResult = verifyFoilAdmissionProof(latentProof);
if (!isDefer(latentResult.verdict ?? Verdict.Accept)) {
  throw new Error(
    `expected latent proof to defer (Abstain); got verdict=${String(latentResult.verdict)}`
  );
}
if (latentResult.verdict !== Verdict.Abstain) {
  throw new Error('expected latent proof verdict to be exactly Verdict.Abstain');
}
// Lossy collapse: the deferring Abstain masquerades as not-accepted in the bool.
if (latentResult.accepted) {
  throw new Error('expected Abstain to collapse to accepted===false (lossy bool)');
}
if (latentResult.reason !== 'verifier-cost-exceeds-constant-bound') {
  throw new Error(
    `unexpected defer reason: ${latentResult.reason}`
  );
}

// assertFoilEdgeAdmission fails closed on the defer path, but throws the more
// specific FoilAdmissionDeferredError (still instanceof FoilAdmissionRejectedError).
let sawDeferredError = false;
try {
  assertFoilEdgeAdmission(latentProof);
  throw new Error('expected latent proof to throw at the hard gate');
} catch (error) {
  if (!(error instanceof FoilAdmissionDeferredError)) {
    throw error;
  }
  if (!(error instanceof FoilAdmissionRejectedError)) {
    throw new Error('expected deferred error to subclass FoilAdmissionRejectedError');
  }
  if (error.verdict !== Verdict.Abstain) {
    throw new Error('expected deferred error to carry the Abstain verdict');
  }
  sawDeferredError = true;
}
if (!sawDeferredError) {
  throw new Error('expected the deferred-error path to be exercised');
}

// The clean-admit path still carries Accept (sign +1) and collapses to accepted.
const acceptResult = verifyFoilAdmissionProof(acceptedProof);
if (acceptResult.verdict !== Verdict.Accept || !isAccept(acceptResult.verdict)) {
  throw new Error('expected clean proof to carry the Accept verdict');
}
if (!acceptResult.accepted) {
  throw new Error('expected Accept to collapse to accepted===true');
}
